class Solution {
public:
    int calculate(string s) {
        int currNum = 0;
        char operation = '+';
        stack<int> nums;
        for (int i = 0; i < s.size(); i++) {
            if (isdigit(s[i])) {
                currNum = currNum * 10 + (s[i] - '0');
            }
            if ((!isdigit(s[i]) && !isspace(s[i])) || i == s.size() - 1) {
                if (operation == '+') {
                    nums.push(currNum);
                } else if (operation == '-') {
                    nums.push(-currNum);
                } else if (operation == '*') {
                    int prevNum = nums.top();
                    nums.pop();
                    nums.push(prevNum * currNum);
                } else if (operation == '/') {
                    int prevNum = nums.top();
                    nums.pop();
                    nums.push(prevNum / currNum);
                }
                operation = s[i];
                currNum = 0;
            }
        }
        int result = 0;
        while (!nums.empty()) {
            result += nums.top();
            nums.pop();
        }
        return result;
    }
};
